do
{
    // runs at least once
} while (condition);

#include <iostream>

using namespace std;

int main()
{
    int i = 1;

    do
    {
        cout << i << endl;
        i++;
    } while (i <= 5);

    return 0;
}

int i = 10;

while (i <= 5) // checked BEFORE — false immediately
{
    cout << i << endl; // never runs
}

int i = 10;

do
{
    cout << i << endl; // runs once, even though condition is false!
} while (i <= 5);

int choice;

do
{
    cout << "1. Play\n2. Settings\n3. Exit\nChoose: ";
    cin >> choice;
} while (choice != 3);

